query_result.query:
{
    "collection": "trans_logs",
    "aggregate": [
        {
            "$match": {
                "createdOn": {
                    "$gte": {
                        "$humanTime": "45 days ago at 18:30"
                    }
                },
                "payment.amount": {
                    "$lt": 10
                },
                "products.goalId": {
                    "$oid": "685e851a620511f4ba002ff6"
                },
                "type": "purchase",
                "$or": [
                    {
                        "emiId": {
                            "$exists": false
                        }
                    },
                    {
                        "isEmiFirstInstallment": true
                    }
                ]
            }
        },
        {
            "$addFields": {
                "isSuccess": {
                    "$cond": [
                        {
                            "$in": [
                                "$status",
                                [
                                    "success",
                                    "partial-refund",
                                    "emandatePending",
                                    "emandateAuthSuccess",
                                    "loggedoutPaid",
                                    "eMandateFailed"
                                ]
                            ]
                        },
                        true,
                        false
                    ]
                }
            }
        },
        {
            "$group": {
                "_id": {
                    "date": {
                        "$dateToString": {
                            "format": "%Y-%m-%d %H:00",
                            "date": {
                                "$add": [
                                    "$createdOn",
                                    19800000
                                ]
                            }
                        }
                    }
                },
                "TotalTransactions": {
                    "$addToSet": "$_id"
                },
                "TotalUsers": {
                    "$addToSet": "$sid"
                },
                "SuccessTransactions": {
                    "$addToSet": {
                        "$cond": [
                            "$isSuccess",
                            "$_id",
                            "$$REMOVE"
                        ]
                    }
                }
            }
        },
        {
            "$project": {
                "_id": 0,
                "Date": "$_id.date",
                "TotalUsers": {
                    "$size": "$TotalUsers"
                },
                "TotalTransactions": {
                    "$size": "$TotalTransactions"
                },
                "SuccessTransactions": {
                    "$size": "$SuccessTransactions"
                }
            }
        }
    ]
}
